export default function compose(...fns) {
  if (fns.length === 0) return x => x;

  return function (...args) {
    let i = fns.length - 1;
    let result = fns[i](...args);

    for (i = i - 1; i >= 0; i--) {
      result = fns[i](result);
    }

    return result;
  };
}

