export default function compose(...fns) {
  if (fns.length === 0) return x => x;

  return function (...args) {
    const lastIndex = fns.length - 1;
    const initial = fns[lastIndex](...args);

    return fns
      .slice(0, lastIndex)
      .reduceRight((acc, fn) => fn(acc), initial);
  };
}
